#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/time.h>
#include <math.h>
#include <omp.h>

#ifdef TIMING
struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
      d2h_time = 0, close_time = 0, total_time = 0;

static void tvsub(struct timeval *t1, struct timeval *t0, struct timeval *td)
{
    td->tv_sec = t1->tv_sec - t0->tv_sec;
    td->tv_usec = t1->tv_usec - t0->tv_usec;
    if (td->tv_usec < 0) {
        td->tv_sec--;
        td->tv_usec += 1000000;
    }
}
#endif

#define REC_LENGTH 53

typedef struct latLong
{
    float lat;
    float lng;
} LatLong;

typedef struct record
{
    char recString[REC_LENGTH];
    float distance;
} Record;

typedef struct
{
    Record *data;
    int size;
    int capacity;
} RecordArray;

typedef struct
{
    LatLong *data;
    int size;
    int capacity;
} LatLongArray;

static void ensureRecordCapacity(RecordArray *records, int needed)
{
    int newCapacity;
    Record *newData;

    if (records->capacity >= needed) return;

    newCapacity = records->capacity ? records->capacity : 1024;
    while (newCapacity < needed) newCapacity *= 2;

    newData = (Record *)realloc(records->data, (size_t)newCapacity * sizeof(Record));
    if (!newData) {
        fprintf(stderr, "out of memory\n");
        exit(1);
    }

    records->data = newData;
    records->capacity = newCapacity;
}

static void ensureLocationCapacity(LatLongArray *locations, int needed)
{
    int newCapacity;
    LatLong *newData;

    if (locations->capacity >= needed) return;

    newCapacity = locations->capacity ? locations->capacity : 1024;
    while (newCapacity < needed) newCapacity *= 2;

    newData = (LatLong *)realloc(locations->data, (size_t)newCapacity * sizeof(LatLong));
    if (!newData) {
        fprintf(stderr, "out of memory\n");
        exit(1);
    }

    locations->data = newData;
    locations->capacity = newCapacity;
}

int loadData(char *filename, RecordArray *records, LatLongArray *locations);
void findLowest(Record *records, float *distances, int numRecords, int topN);
void printUsage(void);
int parseCommandline(int argc, char *argv[], char *filename, int *r, float *lat, float *lng,
                     int *q, int *t, int *p, int *d);

static void euclid_openmp(const LatLong *locations, float *distances, int numRecords, float lat, float lng)
{
    int globalId;

    #pragma omp parallel for schedule(static)
    for (globalId = 0; globalId < numRecords; globalId++) {
        const LatLong *latLong = locations + globalId;
        float dx = lat - latLong->lat;
        float dy = lng - latLong->lng;
        distances[globalId] = (float)sqrt((double)(dx * dx + dy * dy));
    }
}

int main(int argc, char *argv[])
{
    int i = 0;
    float lat, lng;
    int quiet = 0, timing = 0, platform = 0, device = 0;

    RecordArray records;
    LatLongArray locations;
    char filename[100];
    int resultsCount = 10;
    int numRecords;
    float *distances;

    records.data = NULL;
    records.size = 0;
    records.capacity = 0;

    locations.data = NULL;
    locations.size = 0;
    locations.capacity = 0;

    if (parseCommandline(argc, argv, filename, &resultsCount, &lat, &lng,
                         &quiet, &timing, &platform, &device)) {
        printUsage();
        free(records.data);
        free(locations.data);
        return 0;
    }

    numRecords = loadData(filename, &records, &locations);
    if (resultsCount > numRecords) resultsCount = numRecords;

    distances = (float *)malloc(sizeof(float) * (size_t)numRecords);
    if (numRecords > 0 && distances == NULL) {
        fprintf(stderr, "out of memory\n");
        free(records.data);
        free(locations.data);
        return 1;
    }

#ifdef TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif

    euclid_openmp(locations.data, distances, numRecords, lat, lng);

#ifdef TIMING
    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

    findLowest(records.data, distances, numRecords, resultsCount);

    if (!quiet) {
        for (i = 0; i < resultsCount; i++) {
            printf("%s --> Distance=%f\n", records.data[i].recString, records.data[i].distance);
        }
    }

    free(distances);
    free(records.data);
    free(locations.data);

#ifdef TIMING
    printf("Exec: %f\n", kernel_time);
#endif

    return 0;
}

int loadData(char *filename, RecordArray *records, LatLongArray *locations)
{
    FILE *flist, *fp;
    int i = 0;
    char dbname[64];
    int recNum = 0;

    flist = fopen(filename, "r");
    while (!feof(flist)) {
        if (fscanf(flist, "%s\n", dbname) != 1) {
            fprintf(stderr, "error reading filelist\n");
            exit(0);
        }
        fp = fopen(dbname, "r");
        if (!fp) {
            printf("error opening a db\n");
            exit(1);
        }

        while (!feof(fp)) {
            Record record;
            LatLong latLong;
            char substr[6];

            fgets(record.recString, 49, fp);
            fgetc(fp);
            if (feof(fp)) break;

            for (i = 0; i < 5; i++) substr[i] = *(record.recString + i + 28);
            substr[5] = '\0';
            latLong.lat = (float)atof(substr);

            for (i = 0; i < 5; i++) substr[i] = *(record.recString + i + 33);
            substr[5] = '\0';
            latLong.lng = (float)atof(substr);

            ensureLocationCapacity(locations, locations->size + 1);
            ensureRecordCapacity(records, records->size + 1);

            locations->data[locations->size++] = latLong;
            records->data[records->size++] = record;
            recNum++;
        }
        fclose(fp);
    }
    fclose(flist);

    return recNum;
}

void findLowest(Record *records, float *distances, int numRecords, int topN)
{
    int i, j;
    float val;
    int minLoc;
    Record tempRec;
    float tempDist;

    for (i = 0; i < topN; i++) {
        minLoc = i;
        for (j = i; j < numRecords; j++) {
            val = distances[j];
            if (val < distances[minLoc]) minLoc = j;
        }

        tempRec = records[i];
        records[i] = records[minLoc];
        records[minLoc] = tempRec;

        tempDist = distances[i];
        distances[i] = distances[minLoc];
        distances[minLoc] = tempDist;

        records[i].distance = distances[i];
    }
}

int parseCommandline(int argc, char *argv[], char *filename, int *r, float *lat, float *lng,
                     int *q, int *t, int *p, int *d)
{
    int i;
    char flag;

    if (argc < 2) return 1;
    strncpy(filename, argv[1], 100);

    for (i = 1; i < argc; i++) {
        if (argv[i][0] == '-') {
            flag = argv[i][1];
            switch (flag) {
                case 'r':
                    i++;
                    *r = atoi(argv[i]);
                    break;
                case 'l':
                    if (argv[i][2] == 'a') {
                        *lat = (float)atof(argv[i + 1]);
                    } else {
                        *lng = (float)atof(argv[i + 1]);
                    }
                    i++;
                    break;
                case 'h':
                    return 1;
                case 'q':
                    *q = 1;
                    break;
                case 't':
                    *t = 1;
                    break;
                case 'p':
                    i++;
                    *p = atoi(argv[i]);
                    break;
                case 'd':
                    i++;
                    *d = atoi(argv[i]);
                    break;
            }
        }
    }
    if ((*d >= 0 && *p < 0) || (*p >= 0 && *d < 0))
        return 1;
    return 0;
}

void printUsage(void)
{
    printf("Nearest Neighbor Usage\n");
    printf("\n");
    printf("nearestNeighbor [filename] -r [int] -lat [float] -lng [float] [-hqt] [-p [int] -d [int]]\n");
    printf("\n");
    printf("example:\n");
    printf("$ ./nearestNeighbor filelist.txt -r 5 -lat 30 -lng 90\n");
    printf("\n");
    printf("filename     the filename that lists the data input files\n");
    printf("-r [int]     the number of records to return (default: 10)\n");
    printf("-lat [float] the latitude for nearest neighbors (default: 0)\n");
    printf("-lng [float] the longitude for nearest neighbors (default: 0)\n");
    printf("\n");
    printf("-h, --help   Display the help file\n");
    printf("-q           Quiet mode. Suppress all text output.\n");
    printf("-t           Print timing information.\n");
    printf("\n");
    printf("-p [int]     Choose the platform (must choose both platform and device)\n");
    printf("-d [int]     Choose the device (must choose both platform and device)\n");
    printf("\n");
    printf("\n");
    printf("Notes: 1. The filename is required as the first parameter.\n");
    printf("       2. If you declare either the device or the platform,\n");
    printf("          you must declare both.\n\n");
}
